import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Broker Page Templates","description":"Broker Page Templates for FXT Theme","frontmatter":{"title":"Broker Page Templates","description":"Broker Page Templates for FXT Theme","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/broker-page-templates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/broker-page-templates"}],["meta",{"property":"og:title","content":"Broker Page Templates"}],["meta",{"property":"og:description","content":"Broker Page Templates for FXT Theme"}],["meta",{"name":"twitter:title","content":"Broker Page Templates"}],["meta",{"name":"twitter:description","content":"Broker Page Templates for FXT Theme"}]]},"headers":[],"relativePath":"docs/fxt/broker-page-templates.md","filePath":"docs/fxt/broker-page-templates.md"}'),i={name:"docs/fxt/broker-page-templates.md"};function n(l,e,s,d,p,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="broker-page-templates" tabindex="-1">Broker Page Templates <a class="header-anchor" href="#broker-page-templates" aria-label="Permalink to &quot;Broker Page Templates&quot;">​</a></h1><p>You can define different templates for broker review pages in FXT theme.</p><hr><h2 id="using-broker-page-templates" tabindex="-1">Using Broker Page Templates <a class="header-anchor" href="#using-broker-page-templates" aria-label="Permalink to &quot;Using Broker Page Templates&quot;">​</a></h2><p>There are 3 page templates available for displaying <strong>Broker Review Pages</strong> on your website.</p><ol><li><strong>Default Template</strong> - Standard broker review layout (used when no template is selected)</li><li><strong>Overview Template</strong> - Comprehensive broker information display</li><li><strong>Trading Conditions Template</strong> - Focused on trading parameters</li></ol><hr><h2 id="default-template" tabindex="-1">Default Template <a class="header-anchor" href="#default-template" aria-label="Permalink to &quot;Default Template&quot;">​</a></h2><p>The Default template is used automatically when no specific template is selected for a broker page. It provides a standard broker review layout with a comprehensive header section.</p><h3 id="header-section-features" tabindex="-1">Header Section Features <a class="header-anchor" href="#header-section-features" aria-label="Permalink to &quot;Header Section Features&quot;">​</a></h3><ul><li><strong>Broker Logo</strong>: Large, prominent logo display (120px)</li><li><strong>Broker Name</strong>: Main heading with title</li><li><strong>Author Information</strong>: Author block (if enabled in theme options)</li><li><strong>Rating Display</strong>: Overall rating with expandable detailed ratings</li><li><strong>Country Support</strong>: Geographic availability information</li><li><strong>Action Buttons</strong>: Real account and demo account links</li><li><strong>Terms &amp; Conditions</strong>: Popover display of broker terms</li></ul><h3 id="content-area" tabindex="-1">Content Area <a class="header-anchor" href="#content-area" aria-label="Permalink to &quot;Content Area&quot;">​</a></h3><p>The main content area displays the broker review content using the standard broker display template, with hooks for customization before and after the content.</p><hr><h2 id="overview-template" tabindex="-1">Overview Template <a class="header-anchor" href="#overview-template" aria-label="Permalink to &quot;Overview Template&quot;">​</a></h2><p>The Overview template provides a comprehensive view of the broker with detailed information displayed in the header section.</p><h3 id="header-section-features-1" tabindex="-1">Header Section Features <a class="header-anchor" href="#header-section-features-1" aria-label="Permalink to &quot;Header Section Features&quot;">​</a></h3><ul><li><strong>Broker Logo</strong>: Large, prominent logo display (120px)</li><li><strong>Broker Name</strong>: Main heading with title</li><li><strong>Author Information</strong>: Author block (if enabled in theme options)</li><li><strong>Overview Information Grid</strong>: Three-column layout showing: <ul><li><strong>Minimum Deposit</strong>: Payment requirements</li><li><strong>Regulations</strong>: Regulatory bodies and compliance</li><li><strong>Trading Platforms</strong>: Supported trading software</li></ul></li><li><strong>Country Support</strong>: Geographic availability information</li><li><strong>Action Buttons</strong>: Real account and demo account links</li><li><strong>Terms &amp; Conditions</strong>: Popover display of broker terms</li></ul><h3 id="content-area-1" tabindex="-1">Content Area <a class="header-anchor" href="#content-area-1" aria-label="Permalink to &quot;Content Area&quot;">​</a></h3><p>The main content area displays the broker review content using the standard broker display template, with hooks for customization before and after the content.</p><hr><h2 id="trading-conditions-template" tabindex="-1">Trading Conditions Template <a class="header-anchor" href="#trading-conditions-template" aria-label="Permalink to &quot;Trading Conditions Template&quot;">​</a></h2><p>The Trading Conditions template focuses specifically on trading parameters and technical specifications.</p><h3 id="header-section-features-2" tabindex="-1">Header Section Features <a class="header-anchor" href="#header-section-features-2" aria-label="Permalink to &quot;Header Section Features&quot;">​</a></h3><ul><li><strong>Broker Logo</strong>: Large, prominent logo display (120px)</li><li><strong>Broker Name</strong>: Main heading with title</li><li><strong>Author Information</strong>: Author block (if enabled in theme options)</li><li><strong>Trading Conditions Grid</strong>: Three-column layout showing: <ul><li><strong>Minimum Trade Size</strong>: Smallest allowed trade amount</li><li><strong>Average Spread</strong>: Typical spread for EUR/USD pair</li><li><strong>Maximum Leverage</strong>: Highest leverage offered</li></ul></li><li><strong>Country Support</strong>: Geographic availability information</li><li><strong>Action Buttons</strong>: Real account and demo account links</li><li><strong>Terms &amp; Conditions</strong>: Popover display of broker terms</li></ul><h3 id="content-area-2" tabindex="-1">Content Area <a class="header-anchor" href="#content-area-2" aria-label="Permalink to &quot;Content Area&quot;">​</a></h3><p>The main content area displays the broker review content using the standard broker display template, with hooks for customization before and after the content.</p><hr><h2 id="template-selection" tabindex="-1">Template Selection <a class="header-anchor" href="#template-selection" aria-label="Permalink to &quot;Template Selection&quot;">​</a></h2><h3 id="setting-a-broker-template" tabindex="-1">Setting a Broker Template <a class="header-anchor" href="#setting-a-broker-template" aria-label="Permalink to &quot;Setting a Broker Template&quot;">​</a></h3><ol><li>Create or edit a broker page in WordPress</li><li>In the Page Attributes section (right sidebar), look for <strong>Template</strong></li><li>Select either &quot;Overview&quot; or &quot;Trading Conditions&quot; from the dropdown</li><li>Leave as &quot;Default Template&quot; to use the standard broker layout</li><li>Update or publish the broker page</li></ol><h3 id="template-differences" tabindex="-1">Template Differences <a class="header-anchor" href="#template-differences" aria-label="Permalink to &quot;Template Differences&quot;">​</a></h3><ul><li><strong>Default Template</strong>: Standard broker review layout with rating focus</li><li><strong>Overview Template</strong>: Best for comprehensive broker reviews with detailed information</li><li><strong>Trading Conditions Template</strong>: Ideal for technical-focused reviews emphasizing trading parameters</li></ul><hr><h2 id="template-customization" tabindex="-1">Template Customization <a class="header-anchor" href="#template-customization" aria-label="Permalink to &quot;Template Customization&quot;">​</a></h2><h3 id="available-hooks" tabindex="-1">Available Hooks <a class="header-anchor" href="#available-hooks" aria-label="Permalink to &quot;Available Hooks&quot;">​</a></h3><p>All templates provide action hooks for customization:</p><ul><li><code>fxt_broker_before</code>: Executes before the main broker content</li><li><code>fxt_broker_after</code>: Executes after the main broker content</li><li><code>fxt_broker_footer</code>: Executes in the footer area</li></ul><h3 id="header-customization" tabindex="-1">Header Customization <a class="header-anchor" href="#header-customization" aria-label="Permalink to &quot;Header Customization&quot;">​</a></h3><p>The header sections are built using partial templates located in (relative to theme root):</p><ul><li><code>resources/views/broker/default/header.php</code></li><li><code>resources/views/broker/overview/header.php</code></li><li><code>resources/views/broker/trading-conditions/header.php</code></li></ul><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/broker-page-blocks">Creating Broker Review Pages</a></p>',44)])])}const g=t(i,[["render",n]]);export{m as __pageData,g as default};
